  const STORYBOARD_COMPOSER_PLAN_SAVE_RECEIPT_KEYS = Object.freeze([
    "destination", "plan", "scene_count", "execution", "draft_recomputed_on_server", "web_video_plan_persisted",
    ...STORYBOARD_COMPOSER_PLAN_SAVE_FALSE_BOUNDARY_FIELDS
  ]);
