        title, topic, brief, template, platform, aspect_ratio: aspectRatio, duration_seconds: durationSeconds, style, goal, language, idea_choice: ideaChoice,
        creative_directions: creativeDirections, selected_direction: selectedDirection, visual_canon: visualCanon, shots,
        scene_prompts: scenePrompts, meta_ai_prompts: metaAiPrompts, caption, hashtags, cta, cautions, review_before_use: reviewBeforeUse
