  function canAct(page, context) {
    if (!page.action || page.action === "none") return false;
    const capability = context.capabilities[page.action] === true || context.capabilities[page.path] === true;
    const csrfReady = context.session.csrfReady === true || context.bridge.csrfReady === true;
    const bridgeReady = context.bridge.available === true;
    if (page.access === "public") return capability;
    if (WEB_LOCAL_ACTIONS.has(page.action)) return context.session.authenticated === true && csrfReady && capability;
    if (page.action === "start-telegram-link" || page.action === "refresh-link-status") return context.session.authenticated === true && csrfReady && capability;
    if (page.access === "admin" && !serverAuthorizesAdminRoute(context, page.routePath || page.path)) return false;
    if (page.action === "payment-create") {
      const payos = context.paymentOptions && context.paymentOptions.payos;
      return context.session.authenticated === true && csrfReady && bridgeReady && capability && Boolean(payos && payos.topup_catalog_available === true);
    }
    return context.session.authenticated === true && csrfReady && bridgeReady && capability;
  }

  function telegramIdentityLinked(context) {
    return Boolean(
      context && (
        (context.linkStatus && context.linkStatus.linked === true)
        || (context.bridge && context.bridge.available === true)
      )
    );
  }

  function actionBlockReason(page, context) {
    if (page.action === "start-telegram-link" && !telegramConnectionReady(context)) return telegramConnectionBlockReason(context);
    if (page.access === "admin" && !serverAuthorizesAdminRoute(context, page.routePath || page.path)) return "Cần signed authority do máy chủ xác minh cho module này.";
    if (context.session.authenticated !== true && page.access !== "public") return "Cần signed session trước khi tạo yêu cầu.";
    if (WEB_LOCAL_ACTIONS.has(page.action)) {
      const supportAction = String(page.action || "").startsWith("support-");
      if (context.session.csrfReady !== true && context.bridge.csrfReady !== true) return supportAction
        ? "CSRF chưa sẵn sàng; thao tác Support Desk đang được khóa an toàn."
        : "CSRF chưa sẵn sàng; thay đổi kế hoạch Web đang được khóa an toàn.";
      return supportAction ? "Khả năng Support Desk chưa sẵn sàng cho phiên hiện tại." : "Khả năng lập kế hoạch Web chưa sẵn sàng cho phiên hiện tại.";
    }
    const linkAction = page.action === "start-telegram-link" || page.action === "refresh-link-status";
    if (page.access === "member" && !linkAction && !telegramIdentityLinked(context)) return "Cần liên kết Telegram trong Bot trước khi dùng workflow canonical.";
    if (context.bridge.available !== true && page.access !== "public") return "Core Bridge chưa được máy chủ bật cho phiên này.";
    if (context.session.csrfReady !== true && context.bridge.csrfReady !== true) return "CSRF chưa sẵn sàng; yêu cầu write bị khóa an toàn.";
    if (page.action === "payment-create" && context.paymentOptions && context.paymentOptions.payos && context.paymentOptions.payos.topup_catalog_available !== true) return "Danh mục mệnh giá nạp canonical chưa được bridge cấp cho Web. Dùng /naptien trong bot đã liên kết để tạo PayOS QR động.";
    return "Khả năng này chưa được Core Bridge cấp cho phiên hiện tại.";
  }

  function badge(status) {
    const normalized = ALLOWED_STATES.has(status) ? status : "guarded";
    return `<span class="portal-badge" data-status="${normalized}">${safeText(stateLabel(normalized))}</span>`;
  }

  function subtitleAssetOperationsReadBadge(value) {
    const readState = ["loading", "ready", "failed", "guarded"].includes(String(value || ""))
      ? String(value) : "guarded";
    const presentation = {
      loading: { status: "read_only", label: "Đang tải metadata private" },
      ready: { status: "ready", label: "Sẵn sàng" },
      failed: { status: "failed", label: "Chưa tải được metadata" },
      guarded: { status: "guarded", label: "Đang bảo vệ" }
    }[readState];
    return `<span class="portal-badge" data-status="${presentation.status}">${safeText(presentation.label)}</span>`;
  }

  function audioAssetOperationsReadBadge(value) {
    const readState = ["loading", "ready", "failed", "guarded"].includes(String(value || ""))
      ? String(value) : "guarded";
    const presentation = {
      loading: { status: "read_only", label: "Đang tải metadata private" },
      ready: { status: "ready", label: "Sẵn sàng" },
      failed: { status: "failed", label: "Chưa tải được metadata" },
      guarded: { status: "guarded", label: "Đang bảo vệ" }
    }[readState];
    return `<span class="portal-badge" data-status="${presentation.status}">${safeText(presentation.label)}</span>`;
  }

  function pageStatusBadge(page, context) {
    const route = String((page && (page.routePath || page.path)) || "").split("?")[0];
    if (route === "/subtitle/assets") return subtitleAssetOperationsReadBadge(context && context.subtitleAssetOperationsReadState);
    if (route === "/audio/assets") return audioAssetOperationsReadBadge(context && context.audioAssetOperationsReadState);
    return badge(stateFor(page, context));
  }

  function icon(name) { return safeText(ICONS[name] || name || ICONS.default); }

  function displayName(context) {
    const candidate = context.profile.displayName || context.profile.name || context.session.displayName || context.session.email;
    return typeof candidate === "string" && candidate.trim() ? candidate.trim().slice(0, 80) : "Phiên bảo mật đang chờ";
  }

  function displayPageTitle(page, context) {
    const serverTitle = typeof context.title === "string" ? context.title.trim() : "";
    // The server intentionally uses the generic product name for unknown and
    // compatibility paths. A resolved portal page has richer metadata, so do
    // not let that generic placeholder erase its title in the UI/tab.
    return serverTitle && serverTitle !== "TOAN AAS" ? serverTitle : (page.title || "TOAN AAS");
  }

  const NAVIGATION_I18N_KEYS = Object.freeze({
    "Workspace": "nav.workspace",
    "Tổng quan": "nav.dashboard",
    "Chuyển workspace": "nav.workspaceMenu",
    "Guide Center": "nav.guideCenter",
    "Starter Kits": "nav.starterKits",
    "Project Center": "nav.projects",
    "Workboard": "nav.workboard",
    "Asset Vault": "nav.assets",
    "Nội dung & kế hoạch": "nav.contentPlanning",
    "AI Labs & Media": "nav.aiLabs",
    "Tạo mới": "nav.create",
    "Công việc": "nav.work",
    "Job Center": "nav.jobs",
    "Tài sản Bot": "nav.assets",
    "Ví & gói": "nav.wallet",
    "Tài khoản & hỗ trợ": "nav.accountSupport",
    "Tài khoản": "nav.account",
    "Hỗ trợ": "nav.support",
    "Bảng giá": "nav.pricing",
    "Quản trị": "nav.admin"
  });

  function localizedNavigationLabel(label) {
    const source = String(label || "");
    return uiText(NAVIGATION_I18N_KEYS[source] || "", source);
  }

  function localizedPageTitle(page, context) {
    const fallback = displayPageTitle(page, context);
    const path = normalizePath(page && (page.routePath || page.path));
    if (path === "/dashboard") return uiText("nav.dashboard", fallback);
    if (path === "/account") return uiText("account.title", fallback);
    if (path === "/account/interface-language") return uiText("page.interfaceLocale.title", fallback);
    if (path === "/workspace-menu") return uiText("page.workspaceMenu.title", fallback);
    if (path === "/guides") return uiText("page.guideCenter.title", fallback);
    if (path === "/workspace/setup") return uiText("setup.title", fallback);
    if (path === "/starter-kits" || path.startsWith("/starter-kits/")) return uiText("starter.title", fallback);
    return localizedNavigationLabel(fallback);
  }

  function localizedPageDescription(page) {
    const fallback = typeof page.description === "string" ? page.description : "";
    const path = normalizePath(page && (page.routePath || page.path));
    if (path === "/dashboard") return uiText("page.dashboard.description", fallback);
    if (path === "/account") return uiText("page.account.description", fallback);
    if (path === "/account/interface-language") return uiText("page.interfaceLocale.description", fallback);
    if (path === "/workspace-menu") return uiText("page.workspaceMenu.description", fallback);
    if (path === "/guides") return uiText("page.guideCenter.description", fallback);
    if (path === "/workspace/setup") return uiText("page.workspaceSetup.description", fallback);
    if (path === "/starter-kits" || path.startsWith("/starter-kits/")) return uiText("page.starterKits.description", fallback);
    return fallback;
  }

  function initials(name) {
    return safeText((name || "T").trim().charAt(0).toUpperCase() || "T");
  }

  // Admin navigation is a server-authorized projection, not a role map held
  // by the browser.  It intentionally carries no counts, records, bridge
  // diagnostics or write capability; every destination still owns its own
  // signed-session and authority check.
  function adminErpNavigation(context) {
    const source = context && context.adminErpNavigation && typeof context.adminErpNavigation === "object"
      ? context.adminErpNavigation
      : {};
    if (source.read_state !== "ready" || !Array.isArray(source.groups)) return { groups: [], routes: new Set(), canonicalAdmin: false, supportRole: "none", webLocalAdmin: false };
    const groups = [];
    const routes = new Set();
    source.groups.slice(0, 10).forEach((candidate, groupIndex) => {
      if (!candidate || typeof candidate !== "object") return;
      const id = String(candidate.id || `group-${groupIndex}`).trim().toLowerCase().replace(/[^a-z0-9_-]/g, "-").slice(0, 60);
      const title = String(candidate.title || "Admin ERP").trim().slice(0, 96);
      const description = String(candidate.description || "Điều hướng được máy chủ cấp theo quyền phiên hiện tại.").trim().slice(0, 280);
      if (!id || !title) return;
      const modules = [];
      const seen = new Set();
      const rawModules = Array.isArray(candidate.modules) ? candidate.modules : [];
      rawModules.slice(0, 40).forEach((module, moduleIndex) => {
        if (!module || typeof module !== "object") return;
        const route = safeCatalogRoute(String(module.route || module.path || ""));
        if (!route || (route !== "/admin" && !route.startsWith("/admin/")) || seen.has(route)) return;
        const moduleTitle = String(module.title || `Module ${moduleIndex + 1}`).trim().slice(0, 96);
        if (!moduleTitle) return;
        const rawState = String(module.state || module.availability || "read_only").trim().toLowerCase();
        const state = ["available", "canonical_read", "web_native"].includes(rawState)
          ? "read_only"
          : (rawState === "guarded_directory" ? "guarded" : (ALLOWED_STATES.has(rawState) ? rawState : "guarded"));
        seen.add(route);
        routes.add(route);
        modules.push({
          route,
          title: moduleTitle,
          description: String(module.description || "Module được máy chủ bảo vệ theo authority riêng.").trim().slice(0, 280),
          icon: adminRouteIcon(route),
          state,
          authority: String(module.authority || candidate.authority || "server_authorized").trim().slice(0, 48)
        });
      });
      if (modules.length) groups.push({ id, title, description, modules });
    });
    return {
      groups,
      routes,
      canonicalAdmin: source.canonical_admin === true || Boolean(source.access && source.access.canonical_admin === true),
      supportRole: ["admin", "manager", "operator"].includes(String(source.support_role || (source.access && source.access.web_support_scope) || "").trim()) ? String(source.support_role || (source.access && source.access.web_support_scope)).trim() : "none",
      webLocalAdmin: source.web_local_admin === true || Boolean(source.access && source.access.web_local_admin === true)
    };
  }

  function adminRouteIcon(route) {
    if (route === "/admin") return ICONS.admin;
    if (route.includes("support") || route.includes("ticket") || route.includes("handoff") || route.includes("/crm")) return ICONS.support;
    if (route.includes("user") || route.includes("access")) return ICONS.users;
    if (route.includes("payment") || route.includes("wallet") || route.includes("topup") || route.includes("refund") || route.includes("revenue") || route.includes("pricing") || route.includes("package") || route.includes("promo")) return ICONS.payments;
    if (route.includes("job") || route.includes("worker")) return ICONS.jobs;
    if (route.includes("provider")) return ICONS.providers;
    if (route.includes("audit") || route.includes("security")) return ICONS.security;
    if (route.includes("report") || route.includes("growth") || route.includes("trend") || route.includes("lead")) return ICONS.reports;
    return ICONS.system;
  }

  function hasLiveCanonicalAdmin(context) {
    return adminErpNavigation(context).canonicalAdmin === true;
  }

  function serverAuthorizesAdminRoute(context, route) {
    const normalized = normalizePath(String(route || ""));
    const routes = adminErpNavigation(context).routes;
    if (routes.has(normalized)) return true;
    // Detail pages inherit only the exact staff module that the server issued;
    // no arbitrary `/admin/*` prefix becomes navigable or actionable.
    return (
      (normalized.startsWith("/admin/support/") && routes.has("/admin/support"))
      || (normalized.startsWith("/admin/jobs/") && routes.has("/admin/jobs"))
    );
  }

