      const fallbackName = isResize ? "PNG private đã resize" : "PNG private đã chỉnh";
      const pendingMessage = status === "failed" || status === "unavailable"
        ? "Không có PNG tải xuống; kiểm tra ảnh nguồn private và tạo bản sao mới."
        : status === "guarded"
