    if (!canView || !lead || String(lead.id) !== String(page.recordId || "")) return '<article class="portal-page">' + renderHero(page, context) + '<section class="portal-card portal-card-pad">' + renderEmpty(canView ? "Không tìm thấy lead" : "Lead CRM đang được bảo vệ", "Server cần xác minh owner trước khi nạp lead, consent, note và activity.", ICONS.support) + '<a class="portal-button portal-button--primary" href="/crm/leads">Về CRM</a></section></article>';
