    const stageControl = '<section class="portal-card portal-card-pad"><div class="portal-card-header"><div><span class="portal-section-kicker">Pipeline</span><h2 class="portal-card-title">' + safeText(PARTNER_CRM_STAGE_LABELS[lead.stage]) + '</h2><p class="portal-card-subtitle">Server chỉ chấp nhận transition hợp lệ từ stage hiện tại.</p></div>' + badge(lead.stage === "lost" ? "guarded" : lead.stage === "won" ? "ready" : "awaiting_confirm") + '</div><form class="portal-form" data-portal-form data-portal-action="partner-crm-stage" data-portal-route="' + safeText(route) + '" data-portal-confirm="Cập nhật pipeline lead? Thao tác này không gửi liên hệ hoặc tạo kết quả thương mại."><input type="hidden" name="expected_revision" value="' + revision + '"><label class="portal-field"><span>Stage mới</span><select class="portal-select" name="stage"' + (canStage ? "" : " disabled") + '>' + Object.entries(PARTNER_CRM_STAGE_LABELS).map(([key, label]) => '<option value="' + safeText(key) + '"' + (key === lead.stage ? " selected" : "") + '>' + safeText(label) + '</option>').join("") + '</select></label><div class="portal-form-footer"><span class="portal-form-note">Không phải payment, payout, grant hoặc contract.</span><button class="portal-button portal-button--primary" type="submit"' + (canStage ? "" : " disabled") + '>Cập nhật stage</button></div></form></section>';
